INSERT INTO public.services (slug, title, description, content, image_url, sort_order, is_published)
VALUES
  ('consulting', 'Business Consulting', 'Expert guidance to help your business grow and succeed in today''s competitive market.', '<p>Our business consulting services are designed to provide you with strategic insights and actionable plans that drive real results. Our team of experienced consultants works closely with you to understand your unique challenges and opportunities.</p><h2>What We Offer</h2><ul><li>Strategic planning and roadmap development</li><li>Market analysis and competitive intelligence</li><li>Operational efficiency optimization</li><li>Change management support</li><li>Performance metrics and KPI tracking</li></ul>', 'https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=800&q=80', 1, true),
  ('digital-marketing', 'Digital Marketing', 'Comprehensive digital marketing strategies to boost your online presence and drive conversions.', '<p>In the digital age, having a strong online presence is crucial for business success. Our digital marketing team creates data-driven campaigns that reach your target audience at the right time with the right message.</p><h2>Our Services Include</h2><ul><li>Search Engine Optimization (SEO)</li><li>Pay-Per-Click (PPC) advertising</li><li>Social media marketing and management</li><li>Content marketing and strategy</li><li>Email marketing campaigns</li><li>Analytics and reporting</li></ul>', 'https://images.unsplash.com/photo-1432888622747-4eb9a8efeb07?w=800&q=80', 2, true),
  ('web-development', 'Web Development', 'Custom web solutions from responsive websites to complex web applications built for performance.', '<p>We build beautiful, high-performance websites and web applications that not only look great but also deliver exceptional user experiences. Our development team uses the latest technologies and best practices to ensure your web presence stands out.</p><h2>Technologies We Use</h2><ul><li>Next.js and React for modern frontends</li><li>Node.js and Python for robust backends</li><li>PostgreSQL and MongoDB for databases</li><li>AWS and Vercel for cloud deployment</li><li>Tailwind CSS for responsive design</li></ul>', 'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?w=800&q=80', 3, true),
  ('it-support', 'IT Support & Maintenance', 'Reliable IT support services to keep your systems running smoothly around the clock.', '<p>Technology should work for you, not against you. Our IT support and maintenance services ensure your systems are always up and running at peak performance, so you can focus on what matters most — your business.</p><h2>Support Services</h2><ul><li>24/7 help desk support</li><li>Network setup and management</li><li>Server administration</li><li>Security audits and implementation</li><li>Backup and disaster recovery</li><li>Software updates and patch management</li></ul>', 'https://images.unsplash.com/photo-1518770660439-4636190af475?w=800&q=80', 4, true),
  ('cloud-solutions', 'Cloud Solutions', 'Migrate to the cloud and unlock scalability, flexibility, and cost savings for your business.', '<p>Cloud computing has transformed how businesses operate, offering unprecedented flexibility and scalability. Our cloud solutions help you migrate to and manage cloud infrastructure efficiently, ensuring a smooth transition with minimal disruption to your operations.</p><h2>Cloud Services</h2><ul><li>Cloud migration strategy and execution</li><li>Multi-cloud and hybrid cloud setups</li><li>Cloud security and compliance</li><li>Cost optimization and monitoring</li><li>DevOps and CI/CD implementation</li></ul>', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&q=80', 5, true),
  ('data-analytics', 'Data Analytics', 'Transform your raw data into meaningful insights that drive smarter business decisions.', '<p>Data is the new currency of business. Our data analytics services help you collect, process, and analyze your data to uncover valuable insights that give you a competitive edge and help you make more informed decisions.</p><h2>Analytics Capabilities</h2><ul><li>Business intelligence dashboards</li><li>Predictive analytics and forecasting</li><li>Data warehouse design and management</li><li>Real-time analytics pipelines</li><li>Custom reporting and visualization</li></ul>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', 6, true);
INSERT INTO public.products (slug, title, description, content, image_url, sort_order, is_published)
VALUES
  ('enterprise-suite', 'Enterprise Suite', 'Complete business management solution designed for large organizations with complex needs.', '<p>The Enterprise Suite is our flagship product, designed to handle the complex needs of large organizations. It includes everything you need to manage your business operations efficiently and effectively.</p><h2>Key Features</h2><ul><li>Advanced CRM with pipeline management</li><li>Integrated ERP modules</li><li>Real-time analytics dashboard</li><li>Multi-user access with role management</li><li>API integrations with 200+ tools</li><li>24/7 premium support</li></ul>', 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=800&q=80', 1, true),
  ('business-pro', 'Business Pro', 'The perfect solution for growing businesses ready to scale their operations.', '<p>Business Pro is built for ambitious companies looking to streamline their operations and scale efficiently. With powerful automation features and intuitive interfaces, your team will be more productive than ever.</p><h2>Highlights</h2><ul><li>Project and task management</li><li>Team collaboration tools</li><li>Financial reporting and invoicing</li><li>Customer management</li><li>50+ integrations</li></ul>', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=800&q=80', 2, true),
  ('starter-pack', 'Starter Pack', 'Everything a small business needs to get started and grow in the digital age.', '<p>The Starter Pack gives small businesses everything they need to compete in today''s digital marketplace. Simple, affordable, and powerful — it''s the perfect foundation for your business growth.</p><h2>Includes</h2><ul><li>Website and e-commerce setup</li><li>Basic CRM</li><li>Email marketing tools</li><li>Social media management</li><li>Basic analytics</li></ul>', 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=800&q=80', 3, true),
  ('analytics-platform', 'Analytics Platform', 'Deep insights and real-time analytics to power data-driven decision making.', '<p>Our Analytics Platform transforms raw data into actionable insights. With real-time dashboards, custom reports, and predictive analytics, you''ll always have the information you need to stay ahead.</p><h2>Features</h2><ul><li>Real-time data processing</li><li>Customizable dashboards</li><li>Automated reporting</li><li>AI-powered predictions</li><li>Data export and API access</li></ul>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', 4, true),
  ('security-shield', 'Security Shield', 'Enterprise-grade cybersecurity solution to protect your business from threats.', '<p>Protect your business from evolving cyber threats with Security Shield. Our comprehensive security solution monitors, detects, and responds to threats in real time, keeping your data and systems safe.</p><h2>Protection Features</h2><ul><li>Threat detection and response</li><li>DDoS protection</li><li>SSL and encryption management</li><li>Compliance tools (GDPR, HIPAA)</li><li>Security audit reports</li></ul>', 'https://images.unsplash.com/photo-1563986768609-322da13575f3?w=800&q=80', 5, true),
  ('cloud-backup', 'Cloud Backup Pro', 'Automated, encrypted backup solution ensuring your data is always safe and recoverable.', '<p>Never lose critical data again with Cloud Backup Pro. Our automated solution backs up your data continuously, encrypts it for security, and stores it in geographically distributed data centers.</p><h2>Backup Features</h2><ul><li>Continuous real-time backup</li><li>AES-256 encryption</li><li>Geo-redundant storage</li><li>One-click restoration</li><li>99.99% uptime SLA</li></ul>', 'https://images.unsplash.com/photo-1518432031352-d6fc5c10da5a?w=800&q=80', 6, true);
